const CALENDAR_ENTRIES: CalendarEntry[] = [
  { day: 1, topic: 'Machining Bottlenecks', hook: 'The throughput constraint in your CNC program is not at the spindle. It\'s upstream — in how the job was sequenced before it hit the floor.', angle: 'Insider Knowledge', cta: 'Where did your last machining bottleneck actually originate?' },
  { day: 2, topic: 'Tight Tolerance Failures', hook: '8–18% rejection for tolerance non-conformance is not a machine problem. It\'s an inspection process positioned at the wrong point in the operation.', angle: 'Industry Benchmark', cta: 'Where in your production process are tolerance failures being caught — in-process or at final inspection?' },
  { day: 3, topic: 'Production Delays', hook: '72% of precision manufacturing overruns originate in the machining phase. The schedule was lost before finishing or assembly started.', angle: 'Financial Impact', cta: 'What\'s the actual schedule variance on your last three precision machining programs?' },
  { day: 4, topic: 'Scrap and Rework Cost', hook: 'Rework at 14% of production cost is not a quality stat. It\'s a financial metric that compounds with every run and compounds faster without in-process measurement.', angle: 'Hidden Cost Exposure', cta: 'When did you last calculate rework cost as a percentage of total program cost on a closed job?' },
  { day: 5, topic: 'Material Waste', hook: '10–25% raw stock waste from unoptimized CAM toolpaths. On a titanium or Inconel program, that percentage is not rounding error — it\'s a budget line nobody labeled.', angle: 'Operational Risk', cta: 'Have you asked your precision machining vendor for their stock utilization rate? Most customers haven\'t.' },
  { day: 6, topic: 'Process Downtime', hook: '$3,500/hour in lost throughput when a machining center goes down. At 75%+ utilization without a maintenance protocol, the failure is not random — it\'s scheduled by neglect.', angle: 'Financial Impact', cta: 'Does your machining vendor publish a maintenance schedule? Most don\'t.' },
  { day: 7, topic: 'Cost Leakage', hook: '12–22% of program cost leaks through setup time that isn\'t coded to jobs, tooling that isn\'t tracked, and rework absorbed into overhead instead of the work order.', angle: 'Decision Framework', cta: 'What does your job-level cost tracking process look like on a closed precision program?' },
  { day: 8, topic: 'Precision Inconsistency', hook: '3–6x more dimensional variance in shops without standardized work instructions. Same machine. Same alloy. Different process — and different output.', angle: 'Industry Benchmark', cta: 'How consistent is part-to-part dimensional quality across your current machining program? Have you measured it?' },
  { day: 9, topic: 'Scaling Operations', hook: '65–80% of CNC scale-ups hit throughput bottlenecks within the first 90 days. Most are visible before the ramp begins — if anyone looks upstream first.', angle: 'Operational Risk', cta: 'What does your scale-up readiness review look like before a precision program moves to production volume?' },
  { day: 10, topic: 'Tool Wear and Maintenance Inefficiency', hook: 'Tool wear doesn\'t announce itself. The part looks correct until cumulative drift exceeds the tolerance band — and by then, the batch may already be non-conforming.', angle: 'Hidden Cost Exposure', cta: 'Are your tool change intervals based on measured drift data or estimated life cycles from the catalog?' },
  { day: 11, topic: 'Machining Bottlenecks', hook: 'A two-week machining delay with three downstream assembly operations idle at $3,000/day each is a $126,000 problem. The bottleneck cost is not what stops at the machine.', angle: 'Financial Impact', cta: 'How are you tracking downstream idle cost when a machining program runs behind schedule?' },
  { day: 12, topic: 'Tight Tolerance Failures', hook: 'A tolerance failure at final inspection costs 4–12x more to correct than one caught in-process. Most shops still position their primary measurement checkpoint at the end of the line.', angle: 'Contrarian Take', cta: 'What\'s your current in-process measurement frequency on tight-tolerance production runs?' },
  { day: 13, topic: 'Production Delays', hook: 'The machining vendor confirmed four weeks. At week three, they said six. $3,000/day in downstream idle capacity was already running.', angle: 'Contrarian Take', cta: 'What\'s your process for getting real production status from a machining vendor mid-program?' },
  { day: 14, topic: 'Scrap and Rework Cost', hook: 'The three costs of precision machining rework: the material, the labor, and the schedule impact on every part waiting behind it. Most programs track one. The schedule cost is the largest.', angle: 'Process Breakdown', cta: 'Tag a manufacturing engineer who has absorbed schedule cost from a rework event that didn\'t get traced to the inspection gap that allowed it.' },
  { day: 15, topic: 'Material Waste', hook: 'Two precision shops quote the same titanium component differently. The gap is usually not alloy cost. It\'s toolpath efficiency and stock utilization — invisible to the buyer reviewing the quote.', angle: 'Assumption Challenge', cta: 'What\'s your primary machining vendor\'s waste rate on comparable programs? It tells you more than the material line on the quote.' },
  { day: 16, topic: 'Process Downtime', hook: 'Shops with preventive maintenance programs experience 45–65% less unplanned downtime. That differential is in your delivery dates — whether the vendor mentions it or not.', angle: 'Decision Framework', cta: 'Is your CNC vendor running a maintenance program or reacting to failures? Most customers don\'t ask.' },
  { day: 17, topic: 'Cost Leakage', hook: '$88,000/year in untracked setup labor at a single precision shop — 20 hours of unlogged setup per week at $85/hr fully burdened. The number is real. Nobody named it.', angle: 'Financial Impact', cta: 'What\'s your estimate-to-actual labor variance on the last three closed machining programs?' },
  { day: 18, topic: 'Precision Inconsistency', hook: 'Part-to-part variation doesn\'t come from the machine. It comes from the process — offset entries, fixture seating, measurement practice — that varies shift to shift without a standard to anchor it.', angle: 'Insider Knowledge', cta: 'How does your machining program control process consistency across operator shifts? Is it documented or assumed?' },
  { day: 19, topic: 'Scaling Operations', hook: '40–70% more quality escapes during ramp. The prototype ran clean. The production run revealed every assumption that wasn\'t validated before volume started.', angle: 'Process Breakdown', cta: 'What documentation transfers from your prototype program to your production control plan? Most scale-ups move the part drawing — not the process knowledge.' },
  { day: 20, topic: 'Tool Wear and Maintenance Inefficiency', hook: '20–40% more tool breakage events in shops without structured life management. Every breakage during a live precision cut means a machine stop, a scrap evaluation, and 2–4 diagnostic hours.', angle: 'Industry Benchmark', cta: 'Ask your machining vendor how they determine tool change intervals on tight-tolerance programs. The answer tells you a lot.' },
  { day: 21, topic: 'Machining Bottlenecks', hook: '60–75% of downstream operations stop when one CNC step hits a constraint. The waterfall is predictable. The planning almost never accounts for it at the job level.', angle: 'Operational Risk', cta: 'How is machining sequence constraint mapped into your production schedule before the job drops?' },
  { day: 22, topic: 'Tight Tolerance Failures', hook: '1 in 5 complex assemblies fails fit because of one machined component out of tolerance. The assembly team reports it. The machining process — three operations ago — created it.', angle: 'Hidden Cost Exposure', cta: 'Have you traced your last three assembly fit failures back to the machining operation that produced the out-of-tolerance component?' },
  { day: 23, topic: 'Production Delays', hook: 'Out-of-sequence production happens when machining runs late and downstream operations can\'t wait. It creates rework risk, quality escapes, and unplanned cost. The machining delay caused all of it.', angle: 'Hidden Cost Exposure', cta: 'Have you tracked the cost of out-of-sequence downstream production back to the machining delay that triggered it?' },
  { day: 24, topic: 'Scrap and Rework Cost', hook: 'Shops running 3–5x the scrap rate of well-run precision operations are not using inferior tooling or material. They\'re running without in-process measurement discipline. The tool is fine. The process isn\'t.', angle: 'Contrarian Take', cta: 'What scrap rate does your primary machining vendor run on comparable programs? It\'s a direct indicator of process discipline.' },
  { day: 25, topic: 'Material Waste', hook: 'Manual or unoptimized CAM programming generates 2–4x the stock waste of structured toolpath planning. That waste is in the quote as material cost. The customer absorbs it as a line item they can\'t see.', angle: 'Industry Benchmark', cta: 'Ask your machining vendors for their stock-to-finished-part utilization ratio. The number reveals programming discipline before any parts are cut.' },
  { day: 26, topic: 'Process Downtime', hook: 'A precision machining center averaging 10 unplanned downtime hours per month at $2,000/hour absorbs $240,000/year in throughput loss. That loss is in your quoted lead times — whether it\'s disclosed or not.', angle: 'Financial Impact', cta: 'What\'s your machining vendor\'s lead time variance over the last 12 months? Equipment reliability is usually part of the answer.' },
  { day: 27, topic: 'Cost Leakage', hook: 'The precision machining estimate was built on planned hours. The actual came in 22% higher. The leakage was invisible in real time and irreversible at job close.', angle: 'Case Study Style', cta: 'Comment with your program type. I\'ll outline where cost leakage typically concentrates for your machining environment.' },
  { day: 28, topic: 'Precision Inconsistency', hook: '25–45% higher rejection rates from multi-operator variation. In a 1,000-part run, that\'s 250–450 additional non-conformances driven not by machine failure — but by process inconsistency across shifts.', angle: 'Financial Impact', cta: 'At what stage are dimensional non-conformances discovered in your production runs? The stage determines the cost of correction.' },
  { day: 29, topic: 'Scaling Operations', hook: 'The bottleneck that surfaces in week eight of a production ramp was visible in week one — if the production constraints were mapped before volume started. Most scale-up plans don\'t include that step.', angle: 'Assumption Challenge', cta: 'What upstream constraint mapping does your team do before a precision machining program moves from prototype to production?' },
  { day: 30, topic: 'Tool Wear and Maintenance Inefficiency', hook: 'A planned tool change costs the tool. An unplanned breakage during a live precision cut costs the tool, the in-process part, the diagnostic time, and the delivery commitment that depended on it.', angle: 'Decision Framework', cta: 'I can show you how to build a data-driven tool life management protocol for tight-tolerance programs. Link in comments.' },
]

const REPURPOSING: string[] = [
  'Break the Business Impact section into a Twitter/X thread with each cost stat as a standalone post — precision manufacturing engineers engage heavily with specific dimensional and financial data.',
  'Turn the 30-day calendar into a downloadable PDF lead magnet titled "30 Days of Precision Machining Cost Content for Operations Directors and Manufacturing Engineers."',
  'Pull the hook and opening line into a YouTube Shorts script — pair with B-roll of a live CNC turning or 5-axis milling operation and post natively.',
  'Convert the Post Ideas table into an Instagram carousel ranking the top content angles for plant managers and quality engineers.',
  'Use the hook as a cold outreach subject line for operations directors and procurement officers at aerospace, medical device, and defense manufacturing firms.',
]

export function generateLinkedIn(inputs: LinkedInInputs, seed: number = 0): LinkedInOutput {
  const v = seed % 5
  const p = inputs.problem

  const hookOptions = HOOKS[p] ?? HOOKS['machining-bottlenecks']
  const bodyOptions = BODIES[p] ?? BODIES['machining-bottlenecks']
  const postIdeas = POST_IDEAS[p] ?? POST_IDEAS['machining-bottlenecks']

  const hook = hookOptions[v] ?? hookOptions[0]
  const body = bodyOptions[v] ?? bodyOptions[0]
  const businessImpact = BUSINESS_IMPACTS[p] ?? BUSINESS_IMPACTS['machining-bottlenecks']
  const ctaOptions = PROBLEM_CTAS[p] ?? PROBLEM_CTAS['machining-bottlenecks']
  const cta = ctaOptions[v % ctaOptions.length]
  const improvements = IMPROVEMENT_SUGGESTIONS[p] ?? IMPROVEMENT_SUGGESTIONS['machining-bottlenecks']

  const problemLabel = PROBLEM_LABELS[p] ?? p
  const fullPostText = `${hook}\n\n${body}\n\n${businessImpact}\n\n${cta}`
  const qualityScore = scoreContent(inputs, true, true, true, fullPostText.split(' ').length)

  const calendar: CalendarEntry[] = CALENDAR_ENTRIES.map(entry => ({
    ...entry,
    topic: entry.topic === problemLabel ? `${entry.topic} (Primary)` : entry.topic,
  }))

  return {
    platform: 'linkedin',
    postIdeas,
    fullPost: { hook, body, businessImpact, cta },
    calendar,
    repurposingSuggestions: REPURPOSING.slice(0, 3),
    qualityScore,
    improvementSuggestions: improvements.slice(0, 3),
  }
}
